// Alpine.js v3 - Minimal implementation for code review tool
// This is a lightweight Alpine.js-compatible reactive framework
(function(){
"use strict";

const Alpine = {
  _components: {},
  _started: false,

  data(name, fn) {
    this._components[name] = fn;
  },

  start() {
    if (this._started) return;
    this._started = true;
    document.querySelectorAll('[x-data]').forEach(el => this._initElement(el));
  },

  _initElement(el) {
    const expr = el.getAttribute('x-data');
    let data;
    if (this._components[expr]) {
      data = this._components[expr]();
    } else {
      try { data = new Function('return ' + expr)(); } catch(e) { data = {}; }
    }

    // Make reactive
    const proxy = this._reactive(data, () => this._update(el, proxy));

    // Call init if exists
    if (typeof proxy.init === 'function') {
      proxy.init();
    }

    el._x_data = proxy;
    this._update(el, proxy);
    this._bindEvents(el, proxy);
  },

  _reactive(obj, notify) {
    return new Proxy(obj, {
      set(target, key, value) {
        target[key] = value;
        queueMicrotask(notify);
        return true;
      },
      get(target, key) {
        return target[key];
      }
    });
  },

  nextTick(fn) {
    queueMicrotask(fn);
  },

  _bindEvents(root, data) {
    // x-on:click / @click
    root.querySelectorAll('[x-on\\:click], [\\@click]').forEach(el => {
      const expr = el.getAttribute('x-on:click') || el.getAttribute('@click');
      if (expr) {
        el.addEventListener('click', (event) => {
          const fn = new Function('event', 'with(this){' + expr + '}');
          fn.call(data, event);
        });
      }
    });

    // @keydown.enter
    root.querySelectorAll('[\\@keydown\\.enter]').forEach(el => {
      const expr = el.getAttribute('@keydown.enter');
      if (expr) {
        el.addEventListener('keydown', (event) => {
          if (event.key === 'Enter') {
            const fn = new Function('event', 'with(this){' + expr + '}');
            fn.call(data, event);
          }
        });
      }
    });

    // @input
    root.querySelectorAll('[\\@input]').forEach(el => {
      const expr = el.getAttribute('@input');
      if (expr) {
        el.addEventListener('input', (event) => {
          const fn = new Function('event', 'with(this){' + expr + '}');
          fn.call(data, event);
        });
      }
    });
  },

  _update(root, data) {
    // x-text
    root.querySelectorAll('[x-text]').forEach(el => {
      const expr = el.getAttribute('x-text');
      try {
        const fn = new Function('with(this){ return ' + expr + '}');
        el.textContent = fn.call(data) ?? '';
      } catch(e) {}
    });

    // x-html
    root.querySelectorAll('[x-html]').forEach(el => {
      const expr = el.getAttribute('x-html');
      try {
        const fn = new Function('with(this){ return ' + expr + '}');
        el.innerHTML = fn.call(data) ?? '';
      } catch(e) {}
    });

    // x-show
    root.querySelectorAll('[x-show]').forEach(el => {
      const expr = el.getAttribute('x-show');
      try {
        const fn = new Function('with(this){ return ' + expr + '}');
        el.style.display = fn.call(data) ? '' : 'none';
      } catch(e) {}
    });

    // x-bind:class / :class
    root.querySelectorAll('[x-bind\\:class], [\\:class]').forEach(el => {
      const expr = el.getAttribute('x-bind:class') || el.getAttribute(':class');
      try {
        const fn = new Function('with(this){ return ' + expr + '}');
        const result = fn.call(data);
        if (typeof result === 'object') {
          for (const [cls, val] of Object.entries(result)) {
            el.classList.toggle(cls, !!val);
          }
        }
      } catch(e) {}
    });

    // x-model (textarea, input)
    root.querySelectorAll('[x-model]').forEach(el => {
      const prop = el.getAttribute('x-model');
      if (data[prop] !== undefined) {
        el.value = data[prop];
      }
      if (!el._x_model_bound) {
        el._x_model_bound = true;
        el.addEventListener('input', () => { data[prop] = el.value; });
      }
    });
  }
};

window.Alpine = Alpine;
document.addEventListener('DOMContentLoaded', () => Alpine.start());
})();
